.channel-list {
    padding: 1rem;
}

.channel-list-title {
    color: #6c757d;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-bottom: 0.75rem;
    padding: 0 0.5rem;
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-area">
    <div class="message-area-header">
        <h5 class="mb-0"># @ChannelName</h5>
        <p class="text-muted mb-0 small">@ChannelDescription</p>
    </div>
    <div class="message-list" @ref="messageListRef">
        @if (HasMoreMessages)
        {
            <div class="text-center p-2">
                @if (isLoadingMore)
                {
                    <span class="spinner-border spinner-border-sm"></span>
                    <span class="ms-1">Loading...</span>
                }
                else
                {
                    <button class="btn btn-sm btn-link" @onclick="HandleLoadMore">
                        Load older messages
                    </button>
                }
            </div>
        }
        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ThreadSummary="GetThreadSummary(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>
    <MessageInput Placeholder="@($"Message #{ChannelName}")" ButtonText="Send" OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = string.Empty;
    [Parameter] public string ChannelDescription { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool HasMoreMessages { get; set; } = true;
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference messageListRef;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<MessageArea>? dotNetRef;
    private bool isLoadingMore;
    private int previousMessageCount;
    private bool shouldScrollToBottom;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            jsModule = await JS.InvokeAsync<IJSObjectReference>("import", "./js/chat.js");
            await jsModule.InvokeVoidAsync("initScrollDetection", messageListRef, dotNetRef);
        }

        if (shouldScrollToBottom && jsModule is not null)
        {
            shouldScrollToBottom = false;
            await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
        }
    }

    protected override void OnParametersSet()
    {
        if (Messages.Count != previousMessageCount)
        {
            // Scroll to bottom when new messages arrive (not when loading older ones)
            if (Messages.Count > previousMessageCount && !isLoadingMore)
            {
                shouldScrollToBottom = true;
            }
            previousMessageCount = Messages.Count;
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (isLoadingMore || !HasMoreMessages) return;
        await HandleLoadMore();
    }

    private async Task HandleLoadMore()
    {
        if (isLoadingMore) return;
        isLoadingMore = true;
        await OnLoadMore.InvokeAsync();
        isLoadingMore = false;
    }

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.GetValueOrDefault(messageId);

    public async ValueTask DisposeAsync()
    {
        dotNetRef?.Dispose();
        if (jsModule is not null)
        {
            try { await jsModule.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }
    }
}

