@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelList Channels="channels"
                     SelectedChannelId="selectedChannelId"
                     OnChannelSelected="SelectChannel" />
    </div>
    <div class="chat-main @(isThreadOpen ? "" : "chat-main-expanded")">
        @if (selectedChannel is not null)
        {
            <MessageArea ChannelName="@selectedChannel.Name"
                         ChannelDescription="@selectedChannel.Description"
                         Messages="topLevelMessages"
                         ThreadSummaries="threadSummaries"
                         HasMoreMessages="hasMoreMessages"
                         OnLoadMore="LoadMoreMessages"
                         OnSendMessage="SendMessage"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction" />
        }
    </div>
    @if (isThreadOpen && threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private int selectedChannelId;
    private List<Message> allMessages = [];
    private List<Message> topLevelMessages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];
    private bool hasMoreMessages = true;
    private const int PageSize = 50;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        allMessages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        hasMoreMessages = allMessages.Count >= PageSize;
        RebuildViews();
        CloseThread();
        await ChatService.MarkChannelReadAsync(channelId);

        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannel is null) return;
        var older = await ChatService.GetMessagesAsync(selectedChannelId, allMessages.Count, PageSize);
        hasMoreMessages = older.Count >= PageSize;
        allMessages.InsertRange(0, older);
        RebuildViews();
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        allMessages.Add(msg);
        RebuildViews();
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = allMessages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;
        threadReplies = await ChatService.GetThreadAsync(messageId);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendReply(string content)
    {
        if (threadRootMessage is null || selectedChannel is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);
        allMessages.Add(reply);
        RebuildViews();
    }

    private async Task HandleReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);
        // Refresh messages to reflect the updated reaction counts
        if (selectedChannel is not null)
        {
            allMessages = await ChatService.GetMessagesAsync(selectedChannelId, 0, allMessages.Count);
            RebuildViews();
        }
    }

    private void RebuildViews()
    {
        topLevelMessages = allMessages.Where(m => m.ReplyToId is null).ToList();
        threadSummaries = allMessages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)));
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    border-right: 1px solid #dee2e6;
    background: #f8f9fa;
    overflow-y: auto;
    flex-shrink: 0;
}

.chat-main {
    width: 55%;
    display: flex;
